  const data = item.json;

  // ══════════════════════════════════════════════════════════
  // 1. NOTIFICATION AUX RESPONSABLES RH/PERSONNEL/RECRUTEMENT
  // ══════════════════════════════════════════════════════════

  // ── NIVEAU ≤ 10j : RESPO_RH + MANAGER_RH ──
  if (data.niveau_notification === 'RESPO_RH_MANAGER_RH') {

    // 1a. Responsable RH
    if (data.code_respo_rh) {
      const cleRH = `RH_RESPO_RH_${data.code_respo_rh}`;
      if (!notifications[cleRH]) {
        notifications[cleRH] = {
          destinataire_principal: {
            code: data.code_respo_rh,
            nom: data.nom_respo_rh,
            prenom: data.prenom_respo_rh,
            email: data.email_respo_rh,
            chat_id: data.chat_id_respo_rh,
            langue: data.langue_respo_rh,
            bot: data.bot_respo_rh
          },
          type_destinataire: 'RESPO_RH',
          type_notification: 'RESPONSABLES_RH',
          niveau_notification: data.niveau_notification,
          respo_personnel:   { code: data.code_respo_personnel,   nom: data.nom_respo_personnel,   prenom: data.prenom_respo_personnel,   email: data.email_respo_personnel,   chat_id: data.chat_id_respo_personnel,   langue: data.langue_respo_personnel,   bot: data.bot_respo_personnel },
