  if (data.niveau_notification === 'RESPO_PERSONNEL_RECRUTEMENT_COORDINATRICE_RH') {

    // 2a. Responsable Personnel
    if (data.code_respo_personnel) {
      const cleRP = `RH_RESPO_PERSONNEL_${data.code_respo_personnel}`;
      if (!notifications[cleRP]) {
        notifications[cleRP] = {
          destinataire_principal: {
            code: data.code_respo_personnel,
            nom: data.nom_respo_personnel,
            prenom: data.prenom_respo_personnel,
            email: data.email_respo_personnel,
            chat_id: data.chat_id_respo_personnel,
            langue: data.langue_respo_personnel,
