        };
      }
      notifications[cleRR].contrats.push({
        numero_contrat: data.numero_contrat,
        code_salarie: data.code_salarie,
        prenom_salarie: data.prenom_salarie,
        nom_salarie: data.nom_salarie,
        poste_salarie: data.poste_salarie,
        date_entree: data.date_entree,
        libelle_periode_essai: data.libelle_periode_essai,
        type_periode_actuelle: data.type_periode_actuelle,
        date_fin_essai_applicable: data.date_fin_essai_applicable,
        jours_restants: data.jours_restants,
        superieur_nom: data.nom_superieur,
        superieur_prenom: data.prenom_superieur
      });
    }

    // 2c. Coordinatrice RH
    if (data.code_coordinatrice_rh) {
      const cleCRH = `RH_COORDINATRICE_RH_${data.code_coordinatrice_rh}`;
      if (!notifications[cleCRH]) {
        notifications[cleCRH] = {
          destinataire_principal: {
            code: data.code_coordinatrice_rh,
            nom: data.nom_coordinatrice_rh,
            prenom: data.prenom_coordinatrice_rh,
            email: data.email_coordinatrice_rh,
            chat_id: data.chat_id_coordinatrice_rh,
            langue: data.langue_coordinatrice_rh,
            bot: data.bot_coordinatrice_rh
          },
          type_destinataire: 'COORDINATRICE_RH',
          type_notification: 'RESPONSABLES_RH',
          niveau_notification: data.niveau_notification,
          respo_personnel:   { code: data.code_respo_personnel,   nom: data.nom_respo_personnel,   prenom: data.prenom_respo_personnel,   email: data.email_respo_personnel,   chat_id: data.chat_id_respo_personnel,   langue: data.langue_respo_personnel,   bot: data.bot_respo_personnel },
          respo_recrutement: { code: data.code_respo_recrutement, nom: data.nom_respo_recrutement, prenom: data.prenom_respo_recrutement, email: data.email_respo_recrutement, chat_id: data.chat_id_respo_recrutement, langue: data.langue_respo_recrutement, bot: data.bot_respo_recrutement },
          respo_rh:          { code: data.code_respo_rh,          nom: data.nom_respo_rh,          prenom: data.prenom_respo_rh,          email: data.email_respo_rh,          chat_id: data.chat_id_respo_rh,          langue: data.langue_respo_rh,          bot: data.bot_respo_rh },
          manager_rh:        { code: data.code_manager_rh,        nom: data.nom_manager_rh,        prenom: data.prenom_manager_rh,        email: data.email_manager_rh,        chat_id: data.chat_id_manager_rh,        langue: data.langue_manager_rh,        bot: data.bot_manager_rh },
          coordinatrice_rh:  { code: data.code_coordinatrice_rh,  nom: data.nom_coordinatrice_rh,  prenom: data.prenom_coordinatrice_rh,  email: data.email_coordinatrice_rh,  chat_id: data.chat_id_coordinatrice_rh,  langue: data.langue_coordinatrice_rh,  bot: data.bot_coordinatrice_rh },
          contrats: []
        };
      }
      notifications[cleCRH].contrats.push({
        numero_contrat: data.numero_contrat,
        code_salarie: data.code_salarie,
        prenom_salarie: data.prenom_salarie,
        nom_salarie: data.nom_salarie,
        poste_salarie: data.poste_salarie,
        date_entree: data.date_entree,
        libelle_periode_essai: data.libelle_periode_essai,
        type_periode_actuelle: data.type_periode_actuelle,
        date_fin_essai_applicable: data.date_fin_essai_applicable,
