    notifications[cleSup].contrats.push({
      numero_contrat: data.numero_contrat,
      code_salarie: data.code_salarie,
      prenom_salarie: data.prenom_salarie,
      nom_salarie: data.nom_salarie,
      poste_salarie: data.poste_salarie,
      date_entree: data.date_entree,
      libelle_periode_essai: data.libelle_periode_essai,
      type_periode_actuelle: data.type_periode_actuelle,
      date_fin_essai_applicable: data.date_fin_essai_applicable,
      jours_restants: data.jours_restants
    });
  }
});

// ══════════════════════════════════════════════════════════
// CONVERSION EN TABLEAU + ENRICHISSEMENT
// ══════════════════════════════════════════════════════════

const resultats = Object.values(notifications).map(notif => {
  const totalContrats = notif.contrats.length;
  const joursMin = Math.min(...notif.contrats.map(c => c.jours_restants));

  // Email CC : pour RESPO_RECRUTEMENT, mettre RESPO_PERSONNEL en CC et vice-versa
  let emailCC = [];
  if (notif.type_destinataire === 'RESPO_RECRUTEMENT') {
    if (notif.respo_personnel.email && notif.respo_personnel.code !== notif.destinataire_principal.code) {
      emailCC.push(notif.respo_personnel.email);
    }
  }
  if (notif.type_destinataire === 'RESPO_PERSONNEL') {
    if (notif.respo_recrutement.email && notif.respo_recrutement.code !== notif.destinataire_principal.code) {
      emailCC.push(notif.respo_recrutement.email);
    }
  }

  return {
    ...notif,
    email_cc: emailCC.length > 0 ? emailCC.join(',') : null,
    statistiques: {
      total_contrats: totalContrats,
      jours_min: joursMin,
      priorite: notif.niveau_notification
    },
    meta: {
      date_traitement: new Date().toISOString(),
      langue_message: notif.destinataire_principal.langue || 'FRA',
      peut_envoyer_email: !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!(notif.destinataire_principal.chat_id && notif.destinataire_principal.chat_id.trim && notif.destinataire_principal.chat_id.trim() !== '')
    }
  };
});

console.log(`Notifications: ${resultats.length} total`);
console.log(`  RH (≤10j RESPO_RH)       : ${resultats.filter(r => r.type_destinataire === 'RESPO_RH').length}`);
console.log(`  RH (≤10j MANAGER_RH)     : ${resultats.filter(r => r.type_destinataire === 'MANAGER_RH').length}`);
console.log(`  RH (≤15j RESPO_PERSONNEL): ${resultats.filter(r => r.type_destinataire === 'RESPO_PERSONNEL').length}`);
console.log(`  RH (≤15j RESPO_RECRUT.)  : ${resultats.filter(r => r.type_destinataire === 'RESPO_RECRUTEMENT').length}`);
console.log(`  RH (≤15j COORDINATRICE)  : ${resultats.filter(r => r.type_destinataire === 'COORDINATRICE_RH').length}`);
console.log(`  SUPÉRIEURS               : ${resultats.filter(r => r.type_notification === 'SUPERIEUR_HIERARCHIQUE').length}`);

return resultats.map(r => ({ json: r }));

