      RESPO_RH:          '🚨 URGENT - Préparer évaluation immédiatement',
      MANAGER_RH:        '🚨 URGENT - Superviser les évaluations',
      RESPO_PERSONNEL:   '💡 Préparer les évaluations',
      RESPO_RECRUTEMENT: '💡 Anticiper les décisions de recrutement',
      COORDINATRICE_RH:  '💡 Coordonner le suivi des évaluations',
      SUPERIEUR:         "💡 Merci de préparer l'évaluation et de contacter le service RH"
    },
    periode_initiale: '📅 Période INITIALE',
    periode_redoublement: '🔄 Période RENOUVELABLE',
    stats: 'STATISTIQUES',
    total: 'Total dossiers',
    delai: 'Délai minimum',
    jours: 'jour(s)',
    liste: 'LISTE DES SALARIÉS',
    contrat: 'Contrat',
    poste: 'Poste',
    date_entree: 'Entrée',
    date_fin: 'Fin essai',
    restant: 'restant(s)',
    contact_rh: 'Contact RH',
    cordialement: 'Cordialement',
    signature: 'Service SI/IA - Groupe JBEL ANNOUR',
    auto: 'Message automatique'
  }
};

// Fonction de formatage de date
function fmt(d) {
  if (!d) return 'N/A';
  try { return new Date(d).toLocaleDateString('fr-FR'); } catch (e) { return 'N/A'; }
}

// Emoji selon urgence
function emojiJours(j) {
  return j <= 5 ? '🔴' : j <= 10 ? '🟠' : '🟡';
}

// Échapper les caractères spéciaux Markdown Telegram
function escapeMarkdown(text) {
  if (!text) return '';
  return String(text)
    .replace(/\\/g, '\\\\')
    .replace(/[_*[\]()~`>#+=|{}.!\-]/g, '\\$&');
}

function genererMessage(item) {
  const data = item.json;
  const dest = data.destinataire_principal;
  const stats = data.statistiques;
  const isSuperieur = data.type_notification === 'SUPERIEUR_HIERARCHIQUE';
  const typeD = data.type_destinataire;

  // Langue du destinataire (défaut FRA)
  const langue = (dest.langue || 'FRA').toUpperCase();
  const T = TEMPLATES[langue] || TEMPLATES.FRA;

  const sujet    = T.sujets[typeD]  || T.sujets['SUPERIEUR'];
  const intro    = T.intros[typeD]  || T.intros['SUPERIEUR'];
  const action   = T.actions[typeD] || T.actions['SUPERIEUR'];

  // ═══════════════════════════════════════════
  // CORPS EMAIL
  // ═══════════════════════════════════════════
  let body = `Bonjour ${dest.prenom || ''} ${dest.nom || ''},\n\n`;
  body += `${intro}\n\n`;
  body += `${'='.repeat(63)}\n`;
  body += `📊 ${T.stats}\n`;
  body += `${'='.repeat(63)}\n\n`;
  body += `${emojiJours(stats.jours_min)} ${T.total} : ${stats.total_contrats}\n`;
  body += `⏱ ${T.delai} : ${stats.jours_min} ${T.jours}\n\n`;
  body += `${'='.repeat(63)}\n`;
  body += `📋 ${T.liste}\n`;
  body += `${'='.repeat(63)}\n\n`;

  data.contrats.forEach((c, i) => {
    const plLabel = c.type_periode_actuelle === 'INITIALE' ? T.periode_initiale : T.periode_redoublement;

    body += `${i + 1}. ${emojiJours(c.jours_restants)} ${c.prenom_salarie || ''} ${c.nom_salarie || ''}\n`;
    body += `   📄 ${T.contrat}    : ${c.numero_contrat}\n`;
    body += `   👤 Code        : ${c.code_salarie}\n`;
    body += `   💼 ${T.poste}      : ${c.poste_salarie || 'N/A'}\n`;
    body += `   📅 ${T.date_entree} : ${fmt(c.date_entree)}\n`;
    body += `   ${plLabel}\n`;
    body += `   📆 ${T.date_fin}   : ${fmt(c.date_fin_essai_applicable)}\n`;
    body += `   ⏰ ${c.jours_restants} ${T.jours} ${T.restant}\n`;

    // Supérieur affiché uniquement pour les destinataires RH (pas pour le supérieur lui-même)
    if (!isSuperieur && c.superieur_nom && c.superieur_prenom) {
      body += `   👔 Supérieur   : ${c.superieur_prenom} ${c.superieur_nom}\n`;
    }

    body += `   ${action}\n\n`;
  });

  // Contact RH pour le supérieur
  if (isSuperieur) {
    body += `${'='.repeat(63)}\n`;
    if (data.respo_rh && data.respo_rh.email) {
      body += `📞 ${T.contact_rh} : ${data.respo_rh.email}\n`;
    }
    body += `${'='.repeat(63)}\n\n`;
  }

  // CC info si présent
  if (data.email_cc) {
    body += `📋 Copie envoyée à : ${data.email_cc}\n\n`;
  }

  // Signature
  body += `${T.cordialement},\n\n`;
  body += `${T.signature}\n\n`;
  body += `${'━'.repeat(63)}\n`;
  body += `🤖 ${T.auto} - ${fmt(new Date())}\n`;

  // ═══════════════════════════════════════════
  // MESSAGE TELEGRAM
  // ═══════════════════════════════════════════
  let tgMsg = `${emojiJours(stats.jours_min)} *${escapeMarkdown(sujet)}*\n`;
  tgMsg += `${'━'.repeat(21)}\n\n`;
  tgMsg += `👤 *${escapeMarkdown(dest.prenom || '')} ${escapeMarkdown(dest.nom || '')}*\n\n`;
  tgMsg += `📊 ${escapeMarkdown(T.total)} : *${stats.total_contrats}*\n`;
  tgMsg += `⏱ ${escapeMarkdown(T.delai)} : *${stats.jours_min} ${T.jours}*\n\n`;
  tgMsg += `📋 *${escapeMarkdown(T.liste)}*\n\n`;

  // Limiter à 5 contrats dans Telegram pour éviter les messages trop longs
  data.contrats.slice(0, 5).forEach((c, i) => {
    const pe = c.type_periode_actuelle === 'INITIALE' ? '📅' : '🔄';
    tgMsg += `${i + 1}\\. ${emojiJours(c.jours_restants)} *${escapeMarkdown(c.prenom_salarie || '')} ${escapeMarkdown(c.nom_salarie || '')}*\n`;
    tgMsg += `   📄 ${escapeMarkdown(c.numero_contrat)}\n`;
    tgMsg += `   ${pe} ${escapeMarkdown(c.type_periode_actuelle)}\n`;
    tgMsg += `   📆 ${escapeMarkdown(fmt(c.date_fin_essai_applicable))}\n`;
    tgMsg += `   ⏰ ${c.jours_restants} ${escapeMarkdown(T.jours)}\n\n`;
  });

  if (data.contrats.length > 5) {
    tgMsg += `\\.\\.\\. et ${data.contrats.length - 5} autre\\(s\\)\n\n`;
  }

  if (isSuperieur && data.respo_rh && data.respo_rh.email) {
    tgMsg += `📞 ${escapeMarkdown(T.contact_rh)} : ${escapeMarkdown(data.respo_rh.email)}\n`;
  }

  // ═══════════════════════════════════════════
  // RETOUR FINAL
  // ═══════════════════════════════════════════
  return {
    json: {
      ...data,
      messages: {
        email: {
          subject: `${sujet} - ${stats.total_contrats} dossier(s)`,
          body,
          to: dest.email || null,
          cc: data.email_cc || null
        },
        telegram: {
          text: tgMsg,
          parse_mode: 'MarkdownV2',
          chat_id: dest.chat_id && dest.chat_id.trim && dest.chat_id.trim() !== '' ? dest.chat_id : null
        }
      },
      meta: {
        ...data.meta,
        date_generation: new Date().toISOString()
      }
    }
  };
}

return inputData.map(genererMessage);
